# 输入获取
s, t, a, b = map(int, input().split())


# 算法入口
def getResult(s, t, a, b):
    x = 0
    diff = t - s
    while True:
        if str((diff - a * x) / b).endswith(".0") or str((diff + a * x) / b).endswith(".0"):
            return abs(x)
        x += 1


# 算法调用
print(getResult(s, t, a, b))
